arguments.file_text:
namespace sv_78e4f45f24d64bcb915b14301e867974.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@using sv_78e4f45f24d64bcb915b14301e867974.Services
@inject IChatService ChatService
@inject IJSRuntime JS
@rendermode InteractiveServer

<PageTitle>Team Chat</PageTitle>

<div class="chat-layout">
    @* ───── Left sidebar: channel list ───── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var channel in _channels)
                {
                    <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ───── Main message area ───── *@
    <main class="message-area @(_threadOpen ? "thread-open" : "")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h2># @_activeChannel.Name</h2>
                <p>@_activeChannel.Description</p>
            </div>

            <div class="message-list" @ref="_messageListRef" @onscroll="OnMessageListScroll">
                @if (_loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-row" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => _hoveredMessageId = null">
                            <div class="message-bubble">
                                <div class="message-meta">
                                    <span class="author">@msg.Author</span>
                                    <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                                </div>
                                <div class="message-content">@msg.Content</div>

                                @if (msg.Reactions.Count > 0)
                                {
                                    <div class="reaction-row">
                                        @foreach (var r in msg.Reactions)
                                        {
                                            <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                    @onclick="() => ReactAsync(msg.Id, r.Emoji)">
                                                @r.Emoji @r.Users.Count
                                            </button>
                                        }
                                    </div>
                                }

                                @{ var summary = GetThreadSummary(msg.Id); }
                                @if (summary is not null)
                                {
                                    <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                        @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                    </button>
                                }
                            </div>

                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg)">💬 Reply</button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="action-btn" title="Add reaction"
                                                @onclick="() => ToggleEmojiPicker(msg.Id)">😀 React</button>
                                        @if (_emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in _commonEmojis)
                                                {
                                                    <button class="emoji-btn"
                                                            @onclick="() => ReactAsync(msg.Id, emoji)">@emoji</button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="_newMessageText" @bind:event="oninput"
                          placeholder="Type a message…"
                          @onkeydown="OnMessageKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="empty-state">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </main>

    @* ───── Right panel: thread view ───── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <span class="author">@_threadRootMessage.Author</span>
                <span class="timestamp">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                <p>@_threadRootMessage.Content</p>
            </div>

            <div class="thread-replies">
                @if (_threadReplies is not null)
                {
                    @foreach (var reply in _threadReplies)
                    {
                        <div class="thread-reply">
                            <div class="message-meta">
                                <span class="author">@reply.Author</span>
                                <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>
                        </div>
                    }
                }
            </div>

            <div class="thread-input-area">
                <textarea @bind="_threadReplyText" @bind:event="oninput"
                          placeholder="Reply…"
                          @onkeydown="OnThreadKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(_threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    // ── Data ──
    private List<Channel>? _channels;
    private List<Message>? _messages;
    private List<Message>? _threadReplies;
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    // ── UI state ──
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;
    private string _newMessageText = "";
    private string _threadReplyText = "";
    private bool _loadingOlder;
    private int _pageSize = 30;

    private ElementReference _messageListRef;

    private readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    // ── Lifecycle ──

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    // ── Channel selection ──

    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _messages = null;
        _threadSummaries.Clear();
        CloseThread();

        _messages = await ChatService.GetMessagesAsync(channel.Id, 0, _pageSize);
        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh the channel list to update unread counts
        _channels = await ChatService.GetChannelsAsync();

        await ScrollToBottom();
    }

    // ── Sending messages ──

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageText.Trim(), null);
        _newMessageText = "";
        _messages ??= new();
        _messages.Add(sent);

        await ScrollToBottom();
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    // ── Pagination (load older) ──

    private async Task OnMessageListScroll()
    {
        if (_loadingOlder || _activeChannelId is null || _messages is null) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop > 0) return;

        _loadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messages.Count, _pageSize);
        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            BuildThreadSummaries();
        }

        _loadingOlder = false;
    }

    // ── Reactions ──

    private async Task ReactAsync(int messageId, string emoji)
    {
        _emojiPickerMessageId = null;
        await ChatService.AddReactionAsync(messageId, emoji);

        // Refresh messages to reflect the new reaction
        if (_activeChannelId is not null && _messages is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _messages.Count);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    // ── Thread panel ──

    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadOpen = true;
        _threadReplyText = "";
        _threadReplies = await ChatService.GetThreadAsync(rootMessage.Id);
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = null;
        _threadReplyText = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootMessage is null || _activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReplyText.Trim(), _threadRootMessage.Id);
        _threadReplyText = "";
        _threadReplies ??= new();
        _threadReplies.Add(reply);

        // Update thread summary in the main list
        if (_threadSummaries.TryGetValue(_threadRootMessage.Id, out var existing))
        {
            _threadSummaries[_threadRootMessage.Id] = existing with
            {
                ReplyCount = existing.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(_threadRootMessage.Id, 1, reply.SentAt);
        }
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Helpers ──

    private void BuildThreadSummaries()
    {
        if (_messages is null) return;

        var replies = _messages.Where(m => m.ReplyToId is not null).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            _threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt));
        }
    }

    private ThreadSummary? GetThreadSummary(int messageId)
    {
        return _threadSummaries.GetValueOrDefault(messageId);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string desc)
    {
        return desc.Length <= 40 ? desc : desc[..37] + "…";
    }

    private async Task ScrollToBottom()
    {
        await Task.Yield();
        await JS.InvokeVoidAsync("eval",
            "let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight;");
    }
}

/* ── Layout ── */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    color: #1d1c1d;
}

/* ── Sidebar ── */
.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

    .sidebar-header h3 {
        margin: 0;
        color: #fff;
        font-size: 1.1rem;
    }

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    padding: 6px 16px;
    cursor: pointer;
    border-radius: 6px;
    margin: 0 8px;
    transition: background 0.15s;
    position: relative;
}

    .channel-item:hover {
        background: rgba(255, 255, 255, 0.08);
    }

    .channel-item.active {
        background: #1264a3;
        color: #fff;
    }

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    flex: 1;
}

.channel-desc {
    width: 100%;
    font-size: 0.75rem;
    opacity: 0.7;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

.unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ── Main message area ── */
.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #fff;
    min-width: 0;
    transition: flex 0.2s;
}

    .message-area.thread-open {
        max-width: 55%;
    }

.message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

    .message-header h2 {
        margin: 0;
        font-size: 1.15rem;
    }

    .message-header p {
        margin: 4px 0 0;
        font-size: 0.85rem;
        color: #616061;
    }

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 20px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #888;
    font-size: 0.85rem;
}

/* ── Message row ── */
.message-row {
    display: flex;
    align-items: flex-start;
    gap: 8px;
    padding: 6px 0;
    position: relative;
}

    .message-row:hover {
        background: #f8f8f8;
        border-radius: 6px;
    }

.message-bubble {
    flex: 1;
    min-width: 0;
}

.message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
}

.timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    margin-top: 2px;
    line-height: 1.45;
    word-break: break-word;
}

/* ── Reactions ── */
.reaction-row {
    display: flex;
    gap: 4px;
    flex-wrap: wrap;
    margin-top: 4px;
}

.reaction-badge {
    background: #f0f0f0;
    border: 1px solid #e0e0e0;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.15s;
}

    .reaction-badge:hover {
        background: #dceefb;
        border-color: #1264a3;
    }

/* ── Thread link ── */
.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 4px;
}

    .thread-link:hover {
        text-decoration: underline;
    }

/* ── Hover actions ── */
.message-actions {
    display: flex;
    gap: 4px;
    position: absolute;
    right: 4px;
    top: 4px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    font-size: 0.8rem;
    padding: 4px 8px;
    cursor: pointer;
    border-radius: 4px;
    white-space: nowrap;
}

    .action-btn:hover {
        background: #f0f0f0;
    }

.emoji-picker-wrapper {
    position: relative;
}

.emoji-picker {
    position: absolute;
    top: 100%;
    right: 0;
