    flex-shrink: 0;
}

    .message-input-area textarea,
    .thread-input-area textarea {
        flex: 1;
        resize: none;
        border: 1px solid #ccc;
        border-radius: 6px;
        padding: 8px 12px;
        font-size: 0.9rem;
        font-family: inherit;
        outline: none;
        transition: border-color 0.15s;
    }

        .message-input-area textarea:focus,
        .thread-input-area textarea:focus {
            border-color: #1264a3;
        }

.send-btn {
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 6px;
    padding: 8px 16px;
    font-weight: 600;
    font-size: 0.9rem;
    cursor: pointer;
    white-space: nowrap;
    align-self: flex-end;
    transition: background 0.15s;
}

    .send-btn:hover:not(:disabled) {
        background: #005e46;
    }

    .send-btn:disabled {
        opacity: 0.5;
        cursor: default;
    }

/* ── Empty state ── */
.empty-state {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    color: #999;
    font-size: 1.1rem;
}

/* ── Thread panel ── */
.thread-panel {
    width: 25%;
    min-width: 280px;
    border-left: 1px solid #e8e8e8;
    background: #fff;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

    .thread-header h3 {
        margin: 0;
        font-size: 1rem;
    }

.close-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    color: #666;
    padding: 4px 8px;
    border-radius: 4px;
}

    .close-btn:hover {
        background: #f0f0f0;
        color: #333;
    }

.thread-root-quote {
    padding: 12px 16px;
    background: #f8f8f8;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

    .thread-root-quote .author {
        font-size: 0.85rem;
    }

    .thread-root-quote .timestamp {
        font-size: 0.7rem;
        margin-left: 6px;
    }

    .thread-root-quote p {
        margin: 6px 0 0;
        font-size: 0.9rem;
        line-height: 1.4;
    }

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
}

.thread-reply {
    padding: 8px 0;
    border-bottom: 1px solid #f0f0f0;
}

    .thread-reply:last-child {
        border-bottom: none;
    }

.thread-input-area {
    padding: 12px 16px;
}
"}

