toolArgs.file_text:
/* ── Layout ── */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    color: #1d1c1d;
}

/* ── Sidebar ── */
.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

    .sidebar-header h3 {
        margin: 0;
        color: #fff;
        font-size: 1.1rem;
    }

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    padding: 6px 16px;
    cursor: pointer;
    border-radius: 6px;
    margin: 0 8px;
    transition: background 0.15s;
    position: relative;
}

    .channel-item:hover {
        background: rgba(255, 255, 255, 0.08);
    }

    .channel-item.active {
        background: #1264a3;
        color: #fff;
    }

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    flex: 1;
}

.channel-desc {
    width: 100%;
    font-size: 0.75rem;
    opacity: 0.7;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

.unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ── Main message area ── */
.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #fff;
    min-width: 0;
    transition: flex 0.2s;
}

    .message-area.thread-open {
        max-width: 55%;
    }

.message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

    .message-header h2 {
        margin: 0;
        font-size: 1.15rem;
    }

    .message-header p {
        margin: 4px 0 0;
        font-size: 0.85rem;
        color: #616061;
    }

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 20px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #888;
    font-size: 0.85rem;
}

/* ── Message row ── */
.message-row {
    display: flex;
    align-items: flex-start;
    gap: 8px;
    padding: 6px 0;
    position: relative;
}

    .message-row:hover {
        background: #f8f8f8;
        border-radius: 6px;
    }

.message-bubble {
    flex: 1;
    min-width: 0;
}

.message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
}

.timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    margin-top: 2px;
    line-height: 1.45;
    word-break: break-word;
}

/* ── Reactions ── */
.reaction-row {
    display: flex;
    gap: 4px;
    flex-wrap: wrap;
    margin-top: 4px;
}

.reaction-badge {
    background: #f0f0f0;
    border: 1px solid #e0e0e0;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.15s;
}

    .reaction-badge:hover {
        background: #dceefb;
        border-color: #1264a3;
    }

/* ── Thread link ── */
.thread-link {
    background: none;
    border: none;
    color: #1264a3;
